const profile = $('Get Active User Profiles1').first().json;
function safeJSONParse(field) {
  if (!field) return [];
  if (Array.isArray(field)) return field;
  if (typeof field === 'string') {
    try { return JSON.parse(field); } catch (e) { return field.split(',').map(item => item.trim()).filter(Boolean); }
  }
  return [];
}
const jobTitles = safeJSONParse(profile.job_titles);
const locations = safeJSONParse(profile.preferred_locations);
const topJobTitles = jobTitles.slice(0, 2);
const topLocations = locations.slice(0, 2);
const hasPhilippines = topLocations.some(loc => loc.toLowerCase().includes('philippines') || loc.toLowerCase().includes('manila') || loc.toLowerCase().includes('taguig') || loc.toLowerCase().includes('bgc') || loc.toLowerCase().includes('makati') || loc.toLowerCase().includes('quezon'));
const apiCalls = [];
topJobTitles.forEach(jobTitle => {
  if (hasPhilippines) apiCalls.push({ source: 'jsearch', url: 'https://jsearch.p.rapidapi.com/search', query: `${jobTitle} Philippines`, jobTitle, location: 'Philippines', requiresRapidAPI: true, isRSS: false });
  apiCalls.push({ source: 'jsearch', url: 'https://jsearch.p.rapidapi.com/search', query: `${jobTitle} Remote`, jobTitle, location: 'Remote', requiresRapidAPI: true, isRSS: false });
});
apiCalls.push({ source: 'remotive_rss', url: 'https://remotive.com/remote-jobs/software-dev.rss', query: 'Remote Software Dev', jobTitle: 'Software Developer', location: 'Remote', requiresRapidAPI: false, isRSS: true });
apiCalls.push({ source: 'weworkremotely_rss', url: 'https://weworkremotely.com/categories/remote-programming-jobs.rss', query: 'Remote Programming', jobTitle: 'Programmer', location: 'Remote', requiresRapidAPI: false, isRSS: true });
return apiCalls.map(api => ({ json: { ...api, user_id: profile.user_id, email: profile.email } }));

const items = $input.all();
const jobs = [];
for (const item of items) {
  const data = item.json;
  if (data.data && Array.isArray(data.data)) {
    data.data.forEach(j => jobs.push({ external_id: `jsearch-${j.job_id}`, source: 'jsearch', source_url: j.job_apply_link || j.job_google_link || '', title: j.job_title || '', company_name: j.employer_name || '', company_url: j.employer_website || null, location: j.job_city ? `${j.job_city}, ${j.job_country}` : j.job_country || 'Remote', work_type: j.job_is_remote ? 'remote' : 'onsite', employment_type: j.job_employment_type || 'full-time', description: (j.job_description || '').substring(0, 5000), requirements: (j.job_highlights?.Qualifications?.join('\n') || '').substring(0, 2000), posted_date: j.job_posted_at_datetime_utc || new Date().toISOString(), salary_min: j.job_min_salary || null, salary_max: j.job_max_salary || null, scraped_at: new Date().toISOString(), status: 'active' }));
  } else if (data.title && data.link) {
    const stripHtml = (html) => { if (!html) return ''; return html.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 5000); };
    const extractCompany = (text) => { if (!text) return 'Unknown'; const m = text.match(/\sat\s+([A-Z][\w\s&.,()-]+?)(?:\s+-|\s+in|\s+\||$)/i); return m ? m[1].trim() : 'Unknown'; };
    jobs.push({ external_id: data.link.split('/').pop()?.substring(0, 255) || data.link.substring(0, 255), source: data.link.includes('remotive') ? 'remotive' : data.link.includes('weworkremotely') ? 'weworkremotely' : 'rss', source_url: data.link, title: (data.title || '').substring(0, 500), company_name: extractCompany(data.title || '').substring(0, 255), company_url: null, location: 'Remote', work_type: 'remote', employment_type: 'full-time', description: stripHtml(data.description || ''), requirements: '', posted_date: data.pubDate || new Date().toISOString(), salary_min: null, salary_max: null, scraped_at: new Date().toISOString(), status: 'active' });
  }
}
return jobs.map(job => ({ json: job }));

const user = $input.first().json;
if (!user || !user.user_id) throw new Error('No active profile found.');
function safeJSONParse(field) {
  if (!field) return [];
  if (Array.isArray(field)) return field;
  if (typeof field === 'string') { try { return JSON.parse(field); } catch (e) { return field.split(',').map(i => i.trim()).filter(Boolean); } }
  return [];
}
return [{ json: { user_id: user.user_id, profile_id: user.profile_id, email: user.email, full_name: user.full_name || 'User', skills: safeJSONParse(user.skills), experience_years: user.experience_years || 0, job_titles: safeJSONParse(user.job_titles), industries: safeJSONParse(user.industries), min_salary: user.min_salary || 0, max_salary: user.max_salary || 0, preferred_locations: safeJSONParse(user.preferred_locations), work_type: user.work_type || 'any' } }];

const input = $input.first().json;
const jobData = $('Loop Each Job').first().json;
try {
  const responseText = input?.choices?.[0]?.message?.content || '';
  const clean = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const m = clean.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('No JSON in response');
  const p = JSON.parse(m[0]);
  return [{ json: { user_id: jobData.user_id, job_id: jobData.job_id, email: jobData.email, full_name: jobData.full_name, jobTitle: jobData.jobTitle, companyName: jobData.companyName, sourceUrl: jobData.sourceUrl, matchScore: Math.min(100, Math.max(0, Number(p.matchScore) || 0)), reasoning: p.reasoning || '', skillsMatched: Array.isArray(p.skillsMatched) ? p.skillsMatched : [], skillsMissing: Array.isArray(p.skillsMissing) ? p.skillsMissing : [], salaryMatch: Boolean(p.salaryMatch), locationMatch: Boolean(p.locationMatch), recommendation: p.recommendation || 'skip' } }];
} catch (e) {
  return [{ json: { user_id: jobData.user_id, job_id: jobData.job_id, email: jobData.email, full_name: jobData.full_name, jobTitle: jobData.jobTitle, companyName: jobData.companyName, sourceUrl: jobData.sourceUrl, matchScore: 0, reasoning: 'AI scoring failed: ' + e.message, skillsMatched: [], skillsMissing: [], salaryMatch: false, locationMatch: false, recommendation: 'skip' } }];
}
